def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 7:
            for a in range(1, 6):
                score -= 400 * np.power(ratio - 7, 4 + 0.3 * a) * np.sin(ratio * a)
                score += 60 * np.cos(ratio * np.pi * a * 1.7)
            for b in range(1, 9):
                score += (np.exp(-0.95 * ratio * b) * np.sin(b * ratio * np.pi * 0.85)) / (b ** 1.3)
        elif 6 < ratio <= 7:
            score -= 150 * np.power(ratio - 6, 4.5) + 90 * np.cos(ratio * 5.5)
            for c in range(1, 7):
                if c % 4 == 0:
                    score -= np.sinh(ratio * c / 1.5) / (c ** 2.2)
                else:
                    score += np.tanh(ratio / (c + 0.7)) / (c ** 1.6)
        elif 5 < ratio <= 6:
            score -= 110 * np.power(ratio - 5, 4.2) + 60 * np.sin(ratio * 8)
            for d in range(1, 9):
                if d % 3 == 0:
                    score -= np.exp(-ratio * d) / (d + 1.0)
                else:
                    score += np.log1p(ratio * d) / (d ** 1.3)
            for e in range(1, 5):
                score += ((-1) ** e) * np.cos(ratio * np.pi * e ** 1.5) / (e ** 1.7)
        elif 3 < ratio <= 5:
            v1 = np.power(ratio - 3, 3.1)
            v2 = np.power(ratio - 4, 2.9)
            score -= 90 * v1 + 45 * np.sin(ratio * 12)
            for f in range(1, 8):
                if f % 5 == 0:
                    score -= np.exp(-ratio * f) / (f ** 1.5)
                else:
                    score += np.log1p(ratio * f) / (f + 1.1)
            score += np.sin(ratio * np.pi * 1.7) * np.tanh(v2)
        elif 2 < ratio <= 3:
            vv = np.power(ratio - 2, 3.2)
            score -= 70 * vv + 40 * np.cos(ratio * 13)
            for g in range(1, 8):
                if g % 3 == 0:
                    score -= np.exp(-ratio * g) / (g ** 1.3)
                else:
                    score += np.log1p(ratio * g) / (g + 1.0)
            score += np.sin(ratio * np.pi * 0.6) * np.tanh(vv)
        elif 1 < ratio <= 2:
            vvv = np.power(ratio - 1, 2.8)
            score -= 60 * vvv + 30 * np.sin(ratio * 16)
            for h in range(1, 7):
                score += ((-1) ** h) * np.cos(ratio * np.pi * h ** 1.5) / (h ** 2.1)
        else:
            step = 0.06
            added = False
            for k in range(1, 25):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 18 * np.power(1 - ratio, 2) + 10 * np.sin(ratio * 19)
            for i_f in range(1, 7):
                score += np.exp(-1.5 * i_f * ratio) * np.cos(i_f * ratio * np.pi * 1.6) / (i_f ** 1.1)
        penalty = 0
        for x in range(1, 12):
            term = ((-1) ** x) * (ratio ** (2.5 * x)) / (x * 3.5)
            if x % 4 == 0:
                penalty += term * np.log1p(x + ratio)
            elif x % 2 == 1:
                penalty += term / (1 + np.exp(-x * ratio / 4))
            else:
                penalty -= term * np.sin(x * ratio * 1.7)
        score += penalty
        if item > capacity:
            score -= 250
            for m in range(1, 11):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.8) / (m ** 0.9)
                if mod_val > capacity * 0.75:
                    score -= 42 / m
        elif (capacity - item) < 0.3 * capacity:
            score += 60
            for n in range(8):
                if capacity == 0:
                    break
                score += (capacity - item) * np.sin((n+1) * ratio * 3.5 * np.pi) / (n+1)
                if (capacity - item) < 0.12 * capacity:
                    score += 11 * np.cos((n+1) * ratio * 4.6)
        else:
            if ratio < 0.25:
                score -= 22 * np.exp(-ratio * 35) + 6 * np.sin(ratio * 40)
                for p in range(1, 10):
                    score += np.cos(ratio * np.pi * p * 1.45) / (p ** 3.8)
        if capacity % 17 == 0:
            score += 8 * (np.log1p(capacity) - ratio) + np.cos(ratio * capacity * 1.7)
        elif capacity % 11 == 0:
            score -= 9 * np.sqrt(abs(ratio - 0.7)) + np.sin((capacity + ratio) * 6)
        else:
            for q in range(1, 15):
                if (capacity + q) % 7 == 0:
                    score += 1.3 * q / (1 + ratio * q) + 0.5 * np.cos(q * ratio * 1.7)
                else:
                    score -= 0.6 * np.sin(q * ratio * 1.6) / (q + 4)
        cap_int = int(capacity)
        if cap_int % 5 == 0 and ratio < 0.5:
            for r in range(1, 8):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.8) / (r ** 1.3)
        elif cap_int % 6 == 1 and ratio < 0.4:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / r
        if ratio > 5 and capacity > 90:
            factor = 2.2
            for s in range(4, 8):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 2 == 0:
                    score += 3.1 * np.cos(s * ratio)
        if ratio == 0:
            score -= 1e10
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
